css:
* { margin: 0; padding: 0; box-sizing: border-box; }
body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; background: #070b18; color: white; }
.layout { display: flex; min-height: 100vh; }
aside { width: 240px; background: #0d1117; border-right: 1px solid rgba(255,255,255,0.07); padding: 24px 16px; display: flex; flex-direction: column; flex-shrink: 0; }
.brand { font-size: 20px; font-weight: 800; padding: 0 12px; margin-bottom: 32px; }
nav { display: flex; flex-direction: column; gap: 4px; }
.nav-item { display: block; padding: 12px 16px; border-radius: 10px; color: #6b7280; font-size: 14px; font-weight: 500; text-decoration: none; transition: all 0.2s; cursor: pointer; } .nav-item:hover { background: rgba(255,255,255,0.05); color: white; } .nav-item.active { background: rgba(6,182,212,0.15); color: #06b6d4; font-weight: 600; }
main { flex: 1; padding: 28px; overflow-y: auto; }
.topbar { display: flex; justify-content: space-between; align-items: center; margin-bottom: 24px; }
.topbar h1 { font-size: 26px; font-weight: 800; } .topbar p { color: #6b7280; font-size: 13px; margin-top: 2px; }
.period-btns { display: flex; gap: 6px; background: rgba(255,255,255,0.05); padding: 4px; border-radius: 10px; }
.period { padding: 8px 16px; border-radius: 8px; border: none; background: transparent; color: #6b7280; font-size: 13px; font-weight: 600; cursor: pointer; transition: all 0.2s; } .period.active { background: #06b6d4; color: white; }
.kpi-row { display: grid; grid-template-columns: repeat(4,1fr); gap: 16px; margin-bottom: 20px; }
.kpi { background: rgba(255,255,255,0.04); border: 1px solid rgba(255,255,255,0.07); border-radius: 16px; padding: 20px; }
.kpi-top { display: flex; justify-content: space-between; align-items: center; font-size: 12px; color: #6b7280; margin-bottom: 10px; }
.trend { font-weight: 700; } .up { color: #22c55e; } .down { color: #ef4444; }
.kpi-value { font-size: 28px; font-weight: 800; margin-bottom: 12px; }
.kpi-spark { height: 36px; display: flex; align-items: flex-end; gap: 2px; }
.spark-bar { border-radius: 2px; background: rgba(6,182,212,0.4); flex: 1; }
.charts-row { display: grid; grid-template-columns: 2fr 1fr; gap: 16px; margin-bottom: 20px; }
.chart-card { background: rgba(255,255,255,0.04); border: 1px solid rgba(255,255,255,0.07); border-radius: 16px; padding: 20px; }
.chart-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 16px; } .chart-header h3 { font-size: 15px; font-weight: 700; }
.legend { display: flex; gap: 16px; font-size: 12px; }
.leg { display: flex; align-items: center; gap: 6px; color: #6b7280; }
.leg::before { content: ''; width: 12px; height: 3px; border-radius: 2px; display: inline-block; }
.leg.users::before { background: #06b6d4; } .leg.sessions::before { background: #8b5cf6; }
.line-chart { height: 160px; display: flex; align-items: flex-end; gap: 8px; }
.line-col { flex: 1; display: flex; flex-direction: column; align-items: center; gap: 4px; height: 100%; }
.line-col span { font-size: 9px; color: #4b5563; }
.col-bars { flex: 1; display: flex; align-items: flex-end; gap: 2px; width: 100%; }
.col-bar { flex: 1; border-radius: 3px; }
.donut-chart { display: flex; align-items: center; gap: 20px; margin-top: 16px; }
.donut { width: 100px; height: 100px; border-radius: 50%; background: conic-gradient(#06b6d4 0deg 151deg, #3b82f6 151deg 252deg, #8b5cf6 252deg 317deg, #6b7280 317deg 360deg); flex-shrink: 0; }
.donut-legend { display: flex; flex-direction: column; gap: 8px; font-size: 13px; }
.d-item { display: flex; align-items: center; gap: 8px; } .d-dot { width: 8px; height: 8px; border-radius: 50%; flex-shrink: 0; } .organic { background: #06b6d4; } .direct { background: #3b82f6; } .social { background: #8b5cf6; } .other { background: #6b7280; }
.d-item span { flex: 1; color: #9ca3af; } .d-item strong { font-size: 13px; }
.table-card { background: rgba(255,255,255,0.04); border: 1px solid rgba(255,255,255,0.07); border-radius: 16px; padding: 20px; }
.table-header { margin-bottom: 16px; } .table-header h3 { font-size: 15px; font-weight: 700; }
table { width: 100%; border-collapse: collapse; } th { text-align: left; font-size: 12px; color: #6b7280; font-weight: 600; padding: 0 0 12px; } td { padding: 12px 0; font-size: 14px; border-top: 1px solid rgba(255,255,255,0.05); }
.t-up { color: #22c55e; font-size: 16px; } .t-down { color: #ef4444; font-size: 16px; }

