function createSparkBars(id, data) {
  const el = document.getElementById(id);
  const max = Math.max(...data);
  el.innerHTML = data.map(v => `<div class="spark-bar" style="height:${(v/max*100)}%;background:rgba(6,182,212,${0.3 + (v/max)*0.7})"></div>`).join('');
}
createSparkBars('spark1',[30,45,38,52,48,60,55,70,65,80]);
createSparkBars('spark2',[50,60,55,70,65,80,75,90,85,100]);
createSparkBars('spark3',[60,55,58,50,52,48,45,40,42,38]);
createSparkBars('spark4',[20,30,25,40,35,50,45,55,50,65]);

const months = ['Oca','Şub','Mar','Nis','May','Haz','Tem'];
const users = [65,75,60,85,70,90,80];
const sessions = [80,90,75,100,88,110,95];
const lineChart = document.getElementById('line-chart');
const maxVal = Math.max(...users,...sessions);
lineChart.innerHTML = months.map((m,i) => `
  <div class="line-col">
    <div class="col-bars">
      <div class="col-bar" style="height:${(users[i]/maxVal*100)}%;background:rgba(6,182,212,0.7)"></div>
      <div class="col-bar" style="height:${(sessions[i]/maxVal*100)}%;background:rgba(139,92,246,0.7)"></div>
    </div>
    <span>${m}</span>
  </div>
`).join('');
document.querySelectorAll('.period').forEach(btn => { btn.addEventListener('click', function() { document.querySelectorAll('.period').forEach(b => b.classList.remove('active')); this.classList.add('active'); }); });
document.querySelectorAll('.nav-item').forEach(item => { item.addEventListener('click', function() { document.querySelectorAll('.nav-item').forEach(i => i.classList.remove('active')); this.classList.add('active'); }); });
